import './Sidesheet.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont';
import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../helpers/classnames';
import { IconButton } from '../IconButton';
import { Typography } from '../Typography';
import type { SidesheetProps } from './Sidesheet.types';

export const Sidesheet: FC<SidesheetProps> = props => {
	const {
		mode = 'default',
		elevation = 'coplanar',
		placement = 'right',
		size = 'default',
		content,
		children,
		hasDivider = true,
		hasOverlay = false,
		isOpen,
		onClose,
		title,
		className,
		titleNoWrap = true,
		contentPadding,
	} = props;

	const isModalMode = mode === 'modal';
	const isLeftAlign = placement === 'left';
	const isRightAlign = placement === 'right';
	const isCoplanarLayout = elevation === 'coplanar';
	const isAboveLayout = elevation === 'above';

	const containerClass = classNames(
		'dsb_sidesheet',
		{
			dsb_sidesheet_open: isOpen,
			'align-left': isLeftAlign,
			'align-right': isRightAlign,
		},
		className,
	);

	const sheetClass = classNames({
		dsb_sidesheet__sheet: true,
		coplanar: isCoplanarLayout && isOpen,
		'align-left': isLeftAlign && isOpen,
		'align-right': isRightAlign && isOpen,
	});

	const elevationContainerClass = classNames({
		dsb_sidesheet__sheet__elevation: true,
		'is-open': isOpen,
		'align-left': isLeftAlign,
		'align-right': isRightAlign,
		coplanar: isCoplanarLayout,
		'size-large': size === 'large',
		above: isAboveLayout,
		'has-shadow': isModalMode,
	});

	const sheetContentWrapperClass = classNames({
		'dsb_sidesheet__sheet__elevation__content-wrapper': true,
		'has-divider': hasDivider,
		'align-left': isLeftAlign,
		'align-right': isRightAlign,
		coplanar: isCoplanarLayout,
		'size-large': size === 'large',
		above: isAboveLayout,
	});

	const contentHeaderClass = 'dsb_sidesheet__sheet__elevation__content-wrapper__header';

	const sidesheetContentClass = 'dsb_sidesheet__sheet__elevation__content-wrapper__content';

	const contentClass = classNames({
		dsb_sidesheet__content: true,
		modal: isOpen && isModalMode,
		overlay: hasOverlay,
	});

	const titleClass = classNames({
		dsb_sidesheet__title: true,
		'dsb_sidesheet__title_no-wrap': titleNoWrap,
	});

	const handleOverlayClick = (): void => {
		if (isOpen && isModalMode && onClose) {
			onClose();
		}
	};

	const isStringTitle = typeof title === 'string';

	// Создаем кастомные стили для паддингов
	const customPaddingStyle: React.CSSProperties = {};
	if (contentPadding) {
		if (Array.isArray(contentPadding)) {
			customPaddingStyle.padding = `${contentPadding[0]}px ${contentPadding[1]}px ${contentPadding[2]}px ${contentPadding[3]}px`;
		} else {
			customPaddingStyle.padding = contentPadding;
		}
	}

	return (
		<div className={containerClass} data-testid="Sidesheet" role="dialog" aria-modal>
			<div
				className={contentClass}
				onClick={handleOverlayClick}
				role="presentation"
				onKeyDown={(event): void => {
					if (event.key === 'Enter' || event.key === ' ') {
						handleOverlayClick();
					}
				}}
			>
				{children}
				{isOpen && isModalMode && hasOverlay && (
					<div
						className="dsb_sidesheet__overlay-bg"
						onClick={onClose}
						role="button"
						tabIndex={0}
						onKeyDown={(event): void => {
							if (event.key === 'Enter' || event.key === ' ') {
								event.preventDefault();
								onClose?.();
							}
						}}
					/>
				)}
			</div>

			<div className={sheetClass}>
				<div className={elevationContainerClass}>
					<div className={sheetContentWrapperClass} style={customPaddingStyle}>
						<div className={contentHeaderClass}>
							{isStringTitle ? (
								<Typography className={titleClass} variant="h5">
									{title}
								</Typography>
							) : (
								title
							)}

							<IconButton
								iconName={Icons.Close}
								size="large"
								onClick={onClose}
								className="dsb_sidesheet__close-button"
							/>
						</div>
						<div className={sidesheetContentClass}>{content}</div>
					</div>
				</div>
			</div>
		</div>
	);
};
